"""SUBJECTIVE generation tasks (auto-generated + verified). See build_subj_bank.py."""

from dataclasses import dataclass, field
from typing import List


@dataclass
class SubjTask:
    id: str
    category: str
    brief: str
    rubric: List[str]
    constraints: str = ""
    why_ultracode: str = ""


def by_category():
    out = {}
    for t in SUBJECTIVE_TASKS:
        out.setdefault(t.category, []).append(t)
    return out


